import React, { useState } from 'react';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';
import './App.css';

function App() {
  const [customerData, setCustomerData] = useState({});
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const [selectedFile, setSelectedFile] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchLoading, setBatchLoading] = useState(false);

  const [currentView, setCurrentView] = useState('individual');
  const [sidebarOpen, setSidebarOpen] = useState(true);

  const handleInputChange = (newData) => {
    setCustomerData(newData);
  };

  const handleAnalyze = async () => {
    setLoading(true);
    // Simulate API call
    setTimeout(() => {
      setResults({
        probability: 0.75,
        prediction: true,
        feature_importance: {
          Tenure: 0.3,
          SatisfactionScore: 0.25,
          OrderCount: 0.2,
          CashbackAmount: 0.15,
          DaySinceLastOrder: 0.1
        }
      });
      setLoading(false);
    }, 2000);
  };

  const handleReset = () => {
    setCustomerData({});
    setResults(null);
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setSelectedFile(file);
  };

  const handleBatchAnalyze = async () => {
    setBatchLoading(true);
    // Simulate batch processing
    setTimeout(() => {
      setBatchResults({
        total_records: 1500,
        churn_count: 345,
        churn_rate: 0.23,
        download_url: '#'
      });
      setBatchLoading(false);
    }, 3000);
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="app">
      {/* Header */}
      <div className="app-header">
        <div className="header-left">
          <h1 className="app-title">E-commerce ChurnGuard</h1>
          <p className="session-title">iPodSession Title</p>
        </div>
        <div className="header-right">
          <div className="header-stats">
            <div className="stat-item">
              <span className="stat-label">Churn Probability</span>
              <span className="stat-value">12%</span>
            </div>
          </div>
        </div>
      </div>

      <div className="main-layout">
        {/* Sidebar */}
        <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
          <nav className="sidebar-nav">
            {/* Toggle Button inside Nav Bar */}
            <div className="nav-toggle-section">
              <button 
                className="nav-toggle-btn"
                onClick={toggleSidebar}
              >
                <span className="nav-toggle-icon">
                  {sidebarOpen ? '◀' : '▶'}
                </span>
                {sidebarOpen && <span className="nav-toggle-text">Collapse</span>}
              </button>
            </div>

            <button 
              className={`nav-item ${currentView === 'individual' ? 'active' : ''}`}
              onClick={() => setCurrentView('individual')}
            >
              <span className="nav-icon">🔍</span>
              {sidebarOpen && <span className="nav-text">Individual Analysis</span>}
            </button>
            <button 
              className={`nav-item ${currentView === 'batch' ? 'active' : ''}`}
              onClick={() => setCurrentView('batch')}
            >
              <span className="nav-icon">⚡</span>
              {sidebarOpen && <span className="nav-text">Batch Processing</span>}
            </button>
            <button className="nav-item">
              <span className="nav-icon">📊</span>
              {sidebarOpen && <span className="nav-text">Dashboard</span>}
            </button>
          </nav>
        </div>

        {/* Main Content */}
        <div className={`content-area ${!sidebarOpen ? 'expanded' : ''}`}>
          {/* View Title Display */}
          <div className="view-title-section">
            <h2 className="view-title">
              {currentView === 'individual' ? (
                <>
                  <span className="view-icon">🔍111</span>
                  Individual Analysis
                </>
              ) : (
                <>
                  <span className="view-icon">⚡</span>
                  Batch Processing
                </>
              )}
            </h2>
            <p className="view-subtitle">
              {currentView === 'individual' 
                ? "Analyze individual customer data for churn prediction" 
                : "Process multiple customer records in batch for churn analysis"
              }
            </p>
          </div>

          {/* Render Individual Analysis or Batch Analysis based on current view */}
          {currentView === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleAnalyze}
              onReset={handleReset}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={handleFileChange}
              onAnalyze={handleBatchAnalyze}
              loading={batchLoading}
              results={batchResults}
              selectedFile={selectedFile}
            />
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
